class Solution(object):
    def resultsArray(self, nums, k):
        n = len(nums)
        # dp[i] = length of longest consecutive ascending run ending at i
        dp = [1] * n
        for i in range(1, n):
            if nums[i] == nums[i-1] + 1:
                dp[i] = dp[i-1] + 1
        result = []
        for i in range(k-1, n):
            if dp[i] >= k:
                result.append(nums[i])
            else:
                result.append(-1)
        return result
